// Determina qual caminho foi executado e monta a resposta
let resultado;
try {
  resultado = $('Enviar Template WhatsApp').first().json;
} catch(e) {
  try {
    resultado = $('Enviar Texto Livre WhatsApp').first().json;
  } catch(e2) {
    resultado = { error: 'Nenhum envio executado' };
  }
}

const sucesso = resultado && resultado.messages && resultado.messages.length > 0;

return [{
  json: {
    success: sucesso,
    message_id: sucesso ? resultado.messages[0].id : null,
    error: sucesso ? null : (resultado.error || resultado),
    timestamp: new Date().toISOString()
  }
}];
